var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"ARC-EX, 구 알렉산드리아","JPN":"ARC-EX、旧アレクサンドリア","ENG":"ARC-EX, former Alexandria","TWN":"ARC-EX舊亞歷山卓"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"CSE Lv. 3.9","JPN":"CSE Lv.3.9","ENG":"CSE Lv. 3.9","TWN":"CSE Lv. 3.9"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"으… 으…….","JPN":"う……う……","ENG":"Ugh... Ergh...","TWN":"呃……呃……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"쉬잇! 조용히 해……!","JPN":"しーっ！　静かにしろ……！","ENG":"Shh! Keep it down...!","TWN":"噓！安靜……！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"아까 저 새끼 손짓 한 번에 사람들 몸통이 사라지는 거 못 봤어?","JPN":"さっきあいつが手を一回振っただけで人の体が無くなるとこ、お前も見ただろ？","ENG":"Didn't you see it? One flick of that thing's hand and people's torsos vanished.","TWN":"你沒看到剛才那傢伙手一揮人就消失了嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"우리도 그 꼴 나는 거 보고 싶지 않으면 조금만 참아.","JPN":"同じ目に遭いたくなかったらもう少し我慢しろ。","ENG":"If you don't want to end up the same, hold it in.","TWN":"如果不想看到同樣的下場，就忍一忍吧。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"지원 요청을 하자마자 저런 괴물이 나타날 줄이야.","JPN":"支援要請を送った直後にあんな化け物が現れるとは。","ENG":"The moment we called for backup, a monster like that showed up.","TWN":"一請求支援，就出現這種怪物了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"이봐, 아직 대피를 못 한 시민들도 있을 텐데, 어쩔 셈이야?","JPN":"おい、まだ避難していない市民もいるはずだが、どうするつもりだ？","ENG":"Hey, there are still civilians who couldn't evacuate. What's your plan?","TWN":"喂，還有市民沒撤離，你打算怎麼辦？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"구해내야죠.","JPN":"助け出します。","ENG":"We get them out.","TWN":"當然要救他們。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"다들 우리가 구해주길 기다리고 있을 겁니다.","JPN":"皆私たちを待っているはずです。","ENG":"They're waiting for us to save them.","TWN":"大家都在等我們去救他們。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"어떻게 하려고?","JPN":"どうやって？","ENG":"But how?","TWN":"你 打算怎麼做？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"저 아가리 큰 침식체가 사람들 구할 때까지 가만히 있어 준대?","JPN":"あの口デカ侵食体が、救出作業が終わるまで大人しく待ってくれると思うか？","ENG":"Is that big-mouthed C.O. going to sit still while we rescue people?","TWN":"那張大嘴的侵蝕體會等到我們救完人嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"제가 주의를 끌겠습니다.","JPN":"私が注意を引きつけます。","ENG":"I'll draw its attention.","TWN":"我會吸引它的注意。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"어이, 당신……!","JPN":"おい、あんた……！","ENG":"Hey...!","TWN":"喂，你……！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"저는 로터스에서 나고 자랐습니다.","JPN":"私はロータスで生まれ育ちました。","ENG":"I was born and raised in Lotus.","TWN":"我是在洛德斯長大的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"비록 살기도 퍽퍽하고, 범죄가 만연한 곳이지만…….","JPN":"生活は厳しいし、犯罪が蔓延している都市ですが……","ENG":"It's a hard place to live, and crime runs rampant...","TWN":"雖然生活艱辛、犯罪猖獗……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L33_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"적어도 관리국만큼은 질서를 세우고, 정의를 추구해야 하지 않겠습니까?","JPN":"せめて管理局だけは秩序を守り、正義を追求するべきでしょう。","ENG":"But the Administration at least should keep order and pursue justice.","TWN":"但至少管理局必須維持秩序、追求正義，不是嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"제가 이터니움 공명파 발생기로 놈을 유인하겠습니다.","JPN":"私がエタニウム共鳴波発生器でやつを誘き出します。","ENG":"I'll lure it with an Eternium Resonance Pulse Generator.","TWN":"我會用永恆之金共鳴波發生器引誘它。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"그 틈에 아직 대피 못 한 시민들을 데리고 가주세요.","JPN":"その間に、まだ避難できていない市民を連れて逃げてください。","ENG":"While I do, get the civilians who haven't evacuated yet.","TWN":"你們趁機帶走還沒撤離的市民。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"모두 빨리 움직여.","JPN":"皆、早く動くんだ。","ENG":"Move, all of you.","TWN":"大家快行動。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"사람 목숨을 개죽음으로 만들 생각은 없으니까.","JPN":"犠牲を無駄にしたくない。","ENG":"I'm not turning people's lives into a meaningless death.","TWN":"我沒有想要無謂犧牲民眾性命的想法。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"이터니움을 그렇게 처먹고도 배가 고픈 모양이지?","JPN":"エタニウムをあれだけ食い散らかしても、まだ腹が減っているのか。","ENG":"You gobbled down all that Eternium and you're still hungry?","TWN":"吃了這麼多永恆之金，竟然還餓？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"자… 네가 좋아하는 이터니움이다!","JPN":"さあ……お前の好きなエタニウムだ！","ENG":"Come on... here is the Eternium you like!","TWN":" 來……這是你最愛的永恆之金！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWING_SMALL_12"},{"id":"L5_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"헉… 헉…….","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"咳……咳……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"화가 잔뜩 났군.","JPN":"怒り狂っているな。","ENG":"You seem pretty riled up.","TWN":"怒氣滿滿呢。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"좋아. 여기서 끝을 보자.","JPN":"よし。ここで決着をつけるぞ。","ENG":"All right. Let's finish this.","TWN":"好，到此為止吧。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L14_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"덤벼! 이 개 같은 자식아!","JPN":"かかってこい！　このくそ野郎！","ENG":"Come on, you bastard!","TWN":"上吧！該死的傢伙！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"……응?","JPN":"……うん？","ENG":"...Huh?","TWN":"……嗯？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"살…아 있어?","JPN":"生き……てる？","ENG":"I'm... alive?","TWN":"我還……活著嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_QM","text":{"KOREA":"벌써 4종 침식체가 부상한 모양이네.","JPN":"もう第4種侵食体が浮上してきたようね。","ENG":"Looks like a Category 4 C.O. has already emerged.","TWN":"看來4級侵蝕體已經浮上來了呢。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_QM","text":{"KOREA":"이터니움을 매개 삼아 억지로 올라온 거려나?","JPN":"エタニウムを媒介に、無理やり上がって来たのかしら。","ENG":"It forced its way up using Eternium as a catalyst, maybe?","TWN":"是借由永恆之金當媒介，硬被拉上來的嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"다친 덴 없지?","JPN":"怪我はない？","ENG":"You're not hurt, are you?","TWN":"你有沒有哪裡受傷？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"보아하니 혼자 저 녀석을 유인한 것 같은데, 대단하네.","JPN":"一人であいつを誘き寄せていたみたいだけど、すごいわね。","ENG":"From the looks of it, you lured that thing all by yourself. That's impressive.","TWN":"看樣子你一個人把那傢伙引開了，真了不起。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"다, 당신은……?","JPN":"あ、あなたは……？","ENG":"W-who are you...?","TWN":"你、你是……？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"하지만 당신 혼자서 4종 침식체를 유인하겠다는 계획은 너무 위험해.","JPN":"でも、あなた一人で第4種侵食体を相手するなんて、危険すぎる計画よ。","ENG":"Still, trying to bait a Category 4 C.O. alone is too risky.","TWN":"但是光靠你一個人去引誘4級侵蝕體，實在太危險了。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"그래도… 정말 용감하게 잘 버텨줬어.","JPN":"でも……勇気を振り絞ったのね、よく耐えてくれたわ。","ENG":"Even so, you held out bravely. Well done.","TWN":"不過……你真的很勇敢，也堅持得很好。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"이젠 우리한테 맡겨.","JPN":"ここからは私たちに任せなさい。","ENG":"We'll take it from here.","TWN":"接下來就交給我們吧。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님. ARC-EX에 진입 완료했습니다.","JPN":"副戦隊長、ARC-EXに進入完了しました。","ENG":"Deputy Commander, we've entered ARC-EX.","TWN":"副隊長，已經成功進入ARC-EX。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"그쪽으로 간 이터 타입을 제외하곤 이쪽에서 처리 가능한 개체들 같습니다.","JPN":"そちらに向かったイータータイプを除けば、すべてこちらで処理できる個体と思われます。","ENG":"Aside from the Eater headed your way, the rest look handleable on our end.","TWN":"除了跑到那邊去的吞噬型之外，這邊的個體看來都能處理。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"여긴 저희가 알아서 하죠.","JPN":"ここは我々で片付けます。","ENG":"We'll take care of things here.","TWN":"這邊交給我們就行了。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"그렇게 해. 애들 다치지 않게 네가 잘 관리하고.","JPN":"頼んだわ。子どもたちが怪我しないように、あなたがちゃんと仕切って。","ENG":"Do that. Keep the kids safe and manage them well.","TWN":"好。你好好管理，別讓大家受傷。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"그런데, 예고르. 이쪽도 지원 포격이 가능하려나?","JPN":"ところで、イェゴール。こっちにも支援砲撃を頼めるかしら？","ENG":"Also, Yegor, can you provide fire support here?","TWN":"對了，伊高爾，這邊也能支援炮擊嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"물론입니다. 좌표는 이미 <color=#ffd34c>믿음직한 관측관</color>이 따두었으니까요.","JPN":"もちろんです。座標はすでに<color=#ffd34c>頼もしい観測官</color>が計算済みです。","ENG":"Of course. The coordinates are already marked by our <color=#ffd34c>reliable observer</color>.","TWN":"當然。座標早就由那位<color=#ffd34c>可靠的觀測官</color>標好了。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"그럼, 언제 시작하면 되겠습니까?","JPN":"では、開始はいつにしましょう？","ENG":"Then, when shall I start?","TWN":"那麼要什麼時候開始呢？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"후훗, 감히 우리 세계를 침공하려는 멍청이들한텐 당장 뜨거운 맛을 보여줘야지.","JPN":"ふふっ、私たちの世界に土足で踏み込もうとする間抜けどもには、痛い目に遭わせてあげないと。","ENG":"Heh heh, idiots who dare invade our world need a hot welcome right now.","TWN":"哼哼，竟敢入侵我們的世界，得馬上讓這些笨蛋嚐嚐火熱的滋味。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"관리국 제9 포격전대 메이즈. 전투 준비.","JPN":"管理局第9砲撃戦隊メイズ、戦闘準備。","ENG":"Administration 9th Artillery Division Maze. Ready for combat.","TWN":"管理局第9炮擊戰隊梅茲，準備戰鬥。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"목표는 이 용감한 후배님이 끌어낸 침식체 군세.","JPN":"ターゲットは、こちらの勇敢な後輩くんが誘き寄せた侵食体の群れ。","ENG":"Target is the swarm of C.O.s our brave junior drew out.","TWN":"目標是這位勇敢的後輩引出的侵蝕體軍勢。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"적들에게 강철의 눈보라를 선사하자.","JPN":"鋼鉄の吹雪をお見舞いしてあげましょう。","ENG":"Let's present our enemies with a blizzard of steel.","TWN":"送給敵人一場鋼鐵風暴吧。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};